export function findItemById(id) {
  for (const cat of BOTTLE_CATEGORIES) {
    const item = cat.data.find((x) => x.id === id);
    if (item) return { item, categoryId: cat.id, type: "bottle" };
  }
  for (const cat of DRINK_CATEGORIES) {
    const item = cat.data.find((x) => x.id === id);
    if (item) return { item, categoryId: cat.id, type: "drink" };
  }
  // beers (nested)
  const allBeers = [...beers.draft, ...beers.bottles];
  const beer = allBeers.find((x) => x.id === id);
  if (beer) return { item: beer, categoryId: "beers", type: "beer" };
  return null;
}
